                                            </button>
                                            <button onClick={() => setConfirmAction({ type: 'reset', data: s.userId })} className="px-2 py-1 bg-white border border-red-200 text-red-500 rounded text-xs hover:bg-red-50 font-medium">
                                                초기화
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
