                                            <div className="text-xs text-gray-400">가입일: {new Date(s.joinDate).toLocaleDateString()}</div>
                                        </div>
                                        <div className="flex flex-col items-end">
                                            <button 
                                                onClick={() => canCancel && requestCancel(s.savingId)} 
