                                                {canCancel ? '✓ 현재 해지 가능' : `🔒 해지 가능일: ${possibleDateStr} 이후`}
                                            </span>
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}

            <div>
