-- 3. 주가 업데이트 함수 (고정밀 대응)
CREATE OR REPLACE FUNCTION public.v3_update_stock_price(p_stock_id text, p_new_price numeric)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
    UPDATE public.stock_products
    SET "currentPrice" = p_new_price
    WHERE id = p_stock_id;

    INSERT INTO public.stock_price_history ("stockId", price)
    VALUES (p_stock_id, p_new_price);
END;
$$;

-- 4. 고정밀 매수 함수 (CEIL 적용 및 낙전 국고 귀속)
CREATE OR REPLACE FUNCTION public.buy_stock(p_user_id text, p_stock_id text, p_quantity int)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_current_price NUMERIC;
    v_total_cost INT; -- 정수 정산 (올림)
    v_raw_cost NUMERIC;
    v_student_acc_id TEXT;
    v_teacher_acc_id TEXT;
    v_volatility NUMERIC;
    v_new_price NUMERIC;
BEGIN
    -- 정보 조회
    SELECT "currentPrice", volatility INTO v_current_price, v_volatility FROM public.stock_products WHERE id = p_stock_id;
    SELECT "accountId" INTO v_student_acc_id FROM public.accounts WHERE "userId" = p_user_id;
    SELECT "accountId" INTO v_teacher_acc_id FROM public.accounts WHERE "userId" = (SELECT "userId" FROM public.users WHERE role = 'teacher' LIMIT 1);

    -- 실제 비용 계산 (올림 처리)
    v_raw_cost := v_current_price * p_quantity;
    v_total_cost := CEIL(v_raw_cost);

    -- 잔액 확인
    IF (SELECT balance FROM public.accounts WHERE "accountId" = v_student_acc_id) < v_total_cost THEN
        RAISE EXCEPTION '잔액이 부족합니다. (필요: %권)', v_total_cost;
    END IF;

    -- 학생 계좌 출금
    UPDATE public.accounts SET balance = balance - v_total_cost WHERE "accountId" = v_student_acc_id;

    -- 국고로 차액(올림분) 이체
    IF v_total_cost > v_raw_cost THEN
        UPDATE public.accounts SET balance = balance + (v_total_cost - v_raw_cost) WHERE "accountId" = v_teacher_acc_id;
    END IF;

    -- 주식 보유량 업데이트 (평균 매수가는 소수점 유지)
    INSERT INTO public.student_stocks ("userId", "stockId", quantity, "purchasePrice")
    VALUES (p_user_id, p_stock_id, p_quantity, v_current_price)
    ON CONFLICT ("userId", "stockId") 
    DO UPDATE SET 
        "purchasePrice" = (public.student_stocks.quantity * public.student_stocks."purchasePrice" + v_raw_cost) / (public.student_stocks.quantity + p_quantity),
        quantity = public.student_stocks.quantity + p_quantity;

    -- 주가 상승 로직 (지수 모델)
    v_new_price := v_current_price * EXP(COALESCE(v_volatility, 0.01) * p_quantity);
    PERFORM public.v3_update_stock_price(p_stock_id, v_new_price);

    -- 거래 기록
    INSERT INTO public.transactions ("transactionId", "accountId", type, amount, description)
    VALUES (gen_random_uuid(), v_student_acc_id, 'StockBuy', -v_total_cost, (SELECT name FROM public.stock_products WHERE id = p_stock_id) || ' ' || p_quantity || '주 매수');

    RETURN '성공';
END;
$$;

-- 5. 고정밀 매도 함수 (FLOOR 적용 및 수수료/낙전 국고 귀속)
CREATE OR REPLACE FUNCTION public.sell_stock(p_user_id text, p_stock_id text, p_quantity int)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_current_price NUMERIC;
    v_volatility NUMERIC;
    v_new_price NUMERIC;
    v_exec_price NUMERIC;
    v_total_value NUMERIC;
    v_fee_rate NUMERIC;
    v_fee_amount INT;
    v_final_proceeds INT; -- 정수 정산 (버림)
    v_student_acc_id TEXT;
    v_teacher_acc_id TEXT;
    v_owned_qty INT;
BEGIN
    -- 정보 조회
    SELECT "currentPrice", volatility INTO v_current_price, v_volatility FROM public.stock_products WHERE id = p_stock_id;
    SELECT quantity INTO v_owned_qty FROM public.student_stocks WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    SELECT "accountId" INTO v_student_acc_id FROM public.accounts WHERE "userId" = p_user_id;
    SELECT "accountId" INTO v_teacher_acc_id FROM public.accounts WHERE "userId" = (SELECT "userId" FROM public.users WHERE role = 'teacher' LIMIT 1);

    IF v_owned_qty IS NULL OR v_owned_qty < p_quantity THEN
        RAISE EXCEPTION '보유 주식이 부족합니다.';
    END IF;

    -- 가격 하락 및 체결가 계산
    v_new_price := GREATEST(1.0, v_current_price * EXP(-COALESCE(v_volatility, 0.01) * p_quantity));
    v_exec_price := (v_current_price + v_new_price) / 2.0;
    v_total_value := v_exec_price * p_quantity;

    -- 수수료 계산 (CEIL 적용)
    v_fee_rate := (((v_current_price - v_new_price) / v_current_price) * 105.0) + 2.0;
    v_fee_rate := LEAST(33.5, GREATEST(2.0, v_fee_rate));
    v_fee_amount := CEIL(v_total_value * (v_fee_rate / 100.0));

    -- 최종 입금액 (버림 처리)
    v_final_proceeds := FLOOR(v_total_value - v_fee_amount);

    -- 학생 계좌 입금 및 주식 차감
    UPDATE public.accounts SET balance = balance + v_final_proceeds WHERE "accountId" = v_student_acc_id;
    UPDATE public.student_stocks SET quantity = quantity - p_quantity WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    DELETE FROM public.student_stocks WHERE "userId" = p_user_id AND "stockId" = p_stock_id AND quantity <= 0;

    -- 수수료 및 낙전 차액 국고 이체
    UPDATE public.accounts SET balance = balance + (CEIL(v_total_value) - v_final_proceeds) WHERE "accountId" = v_teacher_acc_id;

    -- 주가 업데이트
    PERFORM public.v3_update_stock_price(p_stock_id, v_new_price);

    -- 거래 기록
    INSERT INTO public.transactions ("transactionId", "accountId", type, amount, description)
    VALUES (gen_random_uuid(), v_student_acc_id, 'StockSell', v_final_proceeds, (SELECT name FROM public.stock_products WHERE id = p_stock_id) || ' ' || p_quantity || '주 매도');

    RETURN '성공적으로 판매되었습니다. 입금액: ' || v_final_proceeds || '권';
END;
$$;


-- 기존 함수 삭제 (반환 타입 변경을 위해 필요)
DROP FUNCTION IF EXISTS public.buy_stock(text, text, integer);
DROP FUNCTION IF EXISTS public.sell_stock(text, text, integer);

-- 1. 매수 함수 생성 (수수료 내역 기록 추가)
CREATE OR REPLACE FUNCTION public.buy_stock(p_user_id text, p_stock_id text, p_quantity integer)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_student_acc_id text;
    v_teacher_acc_id text;
    v_stock_price numeric;
    v_total_cost integer;
    v_student_name text;
    v_stock_name text;
BEGIN
    -- 학생 정보 및 계좌 ID 조회
    SELECT a."accountId", u.name INTO v_student_acc_id, v_student_name 
    FROM public.accounts a JOIN public.users u ON a."userId" = u."userId"
    WHERE a."userId" = p_user_id;

    -- 선생님(국고) 계좌 ID 조회
    SELECT "accountId" INTO v_teacher_acc_id FROM public.accounts 
    WHERE "userId" IN (SELECT "userId" FROM public.users WHERE role = 'teacher' LIMIT 1);

    -- 주식 정보 조회
    SELECT "currentPrice", name INTO v_stock_price, v_stock_name FROM public.stock_products WHERE id = p_stock_id;

    -- 매수 총액 계산 (올림 처리)
    v_total_cost := ceil(v_stock_price * p_quantity);

    -- 1. 학생 잔액 차감 및 내역 기록
    UPDATE public.accounts SET balance = balance - v_total_cost WHERE "accountId" = v_student_acc_id;
    INSERT INTO public.transactions ("accountId", type, amount, date, description)
    VALUES (v_student_acc_id, 'StockBuy', -v_total_cost, now(), v_stock_name || ' 매수 (' || p_quantity || '주)');

    -- 2. 국고(선생님)로 금액 입금 및 내역 기록
    UPDATE public.accounts SET balance = balance + v_total_cost WHERE "accountId" = v_teacher_acc_id;
    INSERT INTO public.transactions ("accountId", type, amount, date, description)
    VALUES (v_teacher_acc_id, 'StockBuy', v_total_cost, now(), v_student_name || ' 학생 ' || v_stock_name || ' 매수 대금 입금');

    -- 3. 주식 보유 수량 업데이트
    IF EXISTS (SELECT 1 FROM public.student_stocks WHERE "userId" = p_user_id AND "stockId" = p_stock_id) THEN
        UPDATE public.student_stocks 
        SET quantity = quantity + p_quantity,
            "purchasePrice" = (("purchasePrice" * quantity) + (v_stock_price * p_quantity)) / (quantity + p_quantity)
        WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    ELSE
        INSERT INTO public.student_stocks ("userId", "stockId", quantity, "purchasePrice")
        VALUES (p_user_id, p_stock_id, p_quantity, v_stock_price);
    END IF;
END;
$$;

-- 2. 매도 함수 생성 (가격 충격 모델 적용 및 수수료 내역 기록 추가)
CREATE OR REPLACE FUNCTION public.sell_stock(p_user_id text, p_stock_id text, p_quantity integer)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_student_acc_id text;
    v_teacher_acc_id text;
    v_old_price numeric;
    v_new_price numeric;
    v_exec_price numeric;
    v_volatility numeric;
    v_total_sell_val numeric;
    v_price_impact_pct numeric;
    v_fee_rate numeric;
    v_fee_amount integer;
    v_final_amount integer;
    v_student_name text;
    v_stock_name text;
BEGIN
    -- 기초 정보 조회
    SELECT a."accountId", u.name INTO v_student_acc_id, v_student_name 
    FROM public.accounts a JOIN public.users u ON a."userId" = u."userId"
    WHERE a."userId" = p_user_id;

    SELECT "accountId" INTO v_teacher_acc_id FROM public.accounts 
    WHERE "userId" IN (SELECT "userId" FROM public.users WHERE role = 'teacher' LIMIT 1);

    SELECT "currentPrice", volatility, name INTO v_old_price, v_volatility, v_stock_name 
    FROM public.stock_products WHERE id = p_stock_id;

    -- 가격 충격 및 체결가 계산
    v_new_price := GREATEST(1, v_old_price * exp(-v_volatility * p_quantity));
    v_exec_price := (v_old_price + v_new_price) / 2;
    v_total_sell_val := v_exec_price * p_quantity;

    -- 수수료율 계산 (유동성 페널티)
    v_price_impact_pct := ((v_old_price - v_new_price) / v_old_price) * 100;
    v_fee_rate := LEAST(33.5, GREATEST(2.0, (v_price_impact_pct * 1.05) + 2.0));
    v_fee_amount := ceil(v_total_sell_val * (v_fee_rate / 100));
    v_final_amount := floor(v_total_sell_val - v_fee_amount);

    -- 1. 주식 수량 차감
    UPDATE public.student_stocks SET quantity = quantity - p_quantity 
    WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    DELETE FROM public.student_stocks WHERE quantity <= 0;

    -- 2. 학생 계좌 입금 및 내역 기록
    UPDATE public.accounts SET balance = balance + v_final_amount WHERE "accountId" = v_student_acc_id;
    INSERT INTO public.transactions ("accountId", type, amount, date, description)
    VALUES (v_student_acc_id, 'StockSell', v_final_amount, now(), v_stock_name || ' 매도 (' || p_quantity || '주)');

    -- 3. 국고(선생님)로 수수료 입금 및 내역 기록
    UPDATE public.accounts SET balance = balance + v_fee_amount WHERE "accountId" = v_teacher_acc_id;
    INSERT INTO public.transactions ("accountId", type, amount, date, description)
    VALUES (v_teacher_acc_id, 'StockSell', v_fee_amount, now(), v_student_name || ' 학생 ' || v_stock_name || ' 매도 수수료 입금');

    -- 4. 시장 가격 업데이트 및 이력 기록
    PERFORM public.v3_update_stock_price(p_stock_id, v_new_price);

    RETURN v_stock_name || ' ' || p_quantity || '주 매도 완료 (수수료 ' || round(v_fee_rate, 1) || '%)';
END;
$$;

