-- 4. 최종 매수 함수 (가격 상승 로직 포함)
CREATE OR REPLACE FUNCTION public.buy_stock(p_user_id text, p_stock_id text, p_quantity int)
RETURNS text LANGUAGE plpgsql SECURITY DEFINER AS $$
DECLARE
    v_curr_price NUMERIC;
    v_volatility NUMERIC;
    v_new_price NUMERIC;
    v_raw_cost NUMERIC;
    v_total_cost INT;
    v_student_acc_id TEXT;
    v_teacher_acc_id TEXT;
BEGIN
    -- 정보 조회
    SELECT "currentPrice", COALESCE(volatility, 0.01) INTO v_curr_price, v_volatility FROM public.stock_products WHERE id = p_stock_id;
    SELECT "accountId" INTO v_student_acc_id FROM public.accounts WHERE "userId" = p_user_id;
    SELECT "accountId" INTO v_teacher_acc_id FROM public.accounts WHERE "userId" = (SELECT "userId" FROM public.users WHERE role = 'teacher' LIMIT 1);

    v_raw_cost := v_curr_price * p_quantity;
    v_total_cost := CEIL(v_raw_cost); -- 정수 정산

    -- 잔액 체크
    IF (SELECT balance FROM public.accounts WHERE "accountId" = v_student_acc_id) < v_total_cost THEN
        RAISE EXCEPTION '잔액이 부족합니다. (필요: %권)', v_total_cost;
    END IF;

    -- [핵심] 가격 상승 로직: P_new = P_curr * e^(k * q)
    v_new_price := v_curr_price * EXP(v_volatility * p_quantity);

    -- DB 반영
    UPDATE public.accounts SET balance = balance - v_total_cost WHERE "accountId" = v_student_acc_id;
    IF v_total_cost > v_raw_cost THEN
        UPDATE public.accounts SET balance = balance + (v_total_cost - v_raw_cost) WHERE "accountId" = v_teacher_acc_id;
    END IF;

    INSERT INTO public.student_stocks ("userId", "stockId", quantity, "purchasePrice")
    VALUES (p_user_id, p_stock_id, p_quantity, v_curr_price)
    ON CONFLICT ("userId", "stockId") DO UPDATE SET 
        "purchasePrice" = (public.student_stocks.quantity * public.student_stocks."purchasePrice" + v_raw_cost) / (public.student_stocks.quantity + p_quantity),
        quantity = public.student_stocks.quantity + p_quantity;

    PERFORM public.v3_update_stock_price(p_stock_id, v_new_price);

    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_student_acc_id, 'StockBuy', -v_total_cost, (SELECT name FROM public.stock_products WHERE id = p_stock_id) || ' ' || p_quantity || '주 매수');

    RETURN '성공';
END;
$$;

-- 5. 최종 매도 함수 (가격 하락 로직 포함)
CREATE OR REPLACE FUNCTION public.sell_stock(p_user_id text, p_stock_id text, p_quantity int)
RETURNS text LANGUAGE plpgsql SECURITY DEFINER AS $$
DECLARE
    v_curr_price NUMERIC;
    v_volatility NUMERIC;
    v_new_price NUMERIC;
    v_exec_price NUMERIC;
    v_total_val NUMERIC;
    v_fee_rate NUMERIC;
    v_fee_amt INT;
    v_final_amt INT;
    v_student_acc_id TEXT;
    v_teacher_acc_id TEXT;
BEGIN
    SELECT "currentPrice", COALESCE(volatility, 0.01) INTO v_curr_price, v_volatility FROM public.stock_products WHERE id = p_stock_id;
    SELECT "accountId" INTO v_student_acc_id FROM public.accounts WHERE "userId" = p_user_id;
    SELECT "accountId" INTO v_teacher_acc_id FROM public.accounts WHERE "userId" = (SELECT "userId" FROM public.users WHERE role = 'teacher' LIMIT 1);

    -- 가격 하락 로직: P_new = P_curr * e^(-k * q)
    v_new_price := GREATEST(1.0, v_curr_price * EXP(-v_volatility * p_quantity));
    v_exec_price := (v_curr_price + v_new_price) / 2.0;
    v_total_val := v_exec_price * p_quantity;

    -- 수수료 계산
    v_fee_rate := LEAST(33.5, GREATEST(2.0, (((v_curr_price - v_new_price) / v_curr_price) * 105.0) + 2.0));
    v_fee_amt := CEIL(v_total_val * (v_fee_rate / 100.0));
    v_final_amt := FLOOR(v_total_val - v_fee_amt);

    -- DB 반영
    UPDATE public.accounts SET balance = balance + v_final_amt WHERE "accountId" = v_student_acc_id;
    UPDATE public.accounts SET balance = balance + (CEIL(v_total_val) - v_final_amt) WHERE "accountId" = v_teacher_acc_id;
    UPDATE public.student_stocks SET quantity = quantity - p_quantity WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    DELETE FROM public.student_stocks WHERE quantity <= 0;

    PERFORM public.v3_update_stock_price(p_stock_id, v_new_price);

    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_student_acc_id, 'StockSell', v_final_amt, (SELECT name FROM public.stock_products WHERE id = p_stock_id) || ' ' || p_quantity || '주 매도');

    RETURN '성공';
END;
$$;
```

